function migrateToDefaultRegional(d){
  // Garante todas as regionais canônicas
  _CANONICAL_REGIONAIS.forEach(cr=>{
    let rg = d.regionais.find(r=>Number(r.id)===cr.id || String(r.id)===String(cr.id));
    if(!rg){ d.regionais.push({...cr}); }
    else { rg.id=cr.id; rg.color=rg.color||cr.color; rg.nome=rg.nome||cr.nome; }
  });
  // Garante todos os hubs canônicos
  _CANONICAL_HUBS.forEach(ch=>{
    let tm = d.times.find(t=>Number(t.id)===ch.id || String(t.id)===String(ch.id));
    if(!tm){ d.times.push({...ch}); }
    else {
      tm.id=ch.id;
      // Nome: só sobrescreve variantes legadas (CE06, CE 06, CE06-ALPHA, etc.)
      if(!tm.nome || /^ce[\s\-]?06/i.test(tm.nome||'')) tm.nome=ch.nome;
      tm.regionalId=tm.regionalId||ch.regionalId;
      tm.color=tm.color||ch.color;
    }
  });
  // Garante Aldenir como superAdmin
  const aldenir = d.users.find(u=>u.username==='aldenir');
  if(!aldenir){
    d.users.push({id:1002,username:'aldenir',password:'@RThur20',role:'regional',superAdmin:true,nome:'Aldenir',regionalId:1001,timeId:null,color:'#7c3aed'});
  } else {
    aldenir.password='@RThur20'; aldenir.superAdmin=true; aldenir.role='regional';
    aldenir.color='#7c3aed'; aldenir.nome=aldenir.nome||'Aldenir';
    if(!aldenir.regionalId) aldenir.regionalId=1001;
    aldenir.id=1002;
  }
  // Sellers sem hub → ALPHA (2001)
  d.sellers.forEach(s=>{ if(!s.timeId) s.timeId=2001; });
}
function deduplicateDB(d) {
  ['sellers','times','regionais','users'].forEach(k=>{
    if(!Array.isArray(d[k])) return;
    const seen = new Set();
    d[k] = d[k].filter(x=>{ const key=String(x.id); if(seen.has(key)) return false; seen.add(key); return true; });
  });
}

// Normaliza todas as datas de vendas para YYYY-MM-DD e garante que estão na chave ymKey certa
function _parseVendaDate(raw) {
  if(!raw) return '';
  let ds = String(raw).trim();
  // Já normalizado YYYY-MM-DD
  if(/^\d{4}-\d{2}-\d{2}$/.test(ds)) return ds;
  // ISO UTC: "2026-01-05T00:00:00.000Z" — usa getUTC para evitar timezone off-by-1
  // (Sheets auto-converte datas e GAS devolve como ISO string)
  if(ds.includes('T') || ds.endsWith('Z')){
    const d = new Date(ds);
    if(!isNaN(d)){
      return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`;
    }
  }
  // Formato longo JS: "Fri Jan 23 2026 00:00:00 GMT-0300 (...)"
  const mLong = ds.match(/[A-Z][a-z]{2}\s+([A-Z][a-z]{2})\s+(\d{1,2})\s+(\d{4})/);
  if(mLong && _MONTHS_MAP[mLong[1]]) {
    return `${mLong[3]}-${_MONTHS_MAP[mLong[1]]}-${mLong[2].padStart(2,'0')}`;
  }
  // DD/MM/YYYY ou DD-MM-YYYY ou DD.MM.YYYY
  const p = ds.split(/[\/\-\.]/);
  if(p.length === 3) {
    if(p[0].length === 4) return `${p[0]}-${p[1].padStart(2,'0')}-${p[2].padStart(2,'0')}`;
    if(p[2].length === 4) return `${p[2]}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}`;
  }
  // Fallback: tenta Date nativo e extrai data UTC
  try {
    const d = new Date(ds);
    if(!isNaN(d)) return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`;
  } catch(e){}
  return '';
}
function normalizeVendaDates(d) {
  if(!d.vendas || typeof d.vendas !== 'object') { d.vendas = {}; return; }
  const newVendas = {};
  Object.keys(d.vendas).forEach(key => {
    (d.vendas[key] || []).forEach(v => {
      const ds = _parseVendaDate(v.date);
      v.date = ds || v.date; // mantém original só se falhar completamente
      // Calcula o ymKey correto a partir da data normalizada
      let targetKey = key;
      if(ds && /^\d{4}-\d{2}-\d{2}$/.test(ds)) {
        const parts = ds.split('-');
        targetKey = parts[0] + parts[1]; // YYYYMM
      }
      if(!newVendas[targetKey]) newVendas[targetKey] = [];
      newVendas[targetKey].push(v);
    });
  });
  // Remove duplicatas por id dentro de cada mês
  Object.keys(newVendas).forEach(k => {
    const seen = new Set();
    newVendas[k] = newVendas[k].filter(v => { const id = String(v.id); if(seen.has(id)) return false; seen.add(id); return true; });
  });
  d.vendas = newVendas;
}